-- Sprint 26.0.3 — NEEJEE Taxonomy Schema + Seed (FK-drop strategy, bulletproof)
-- Drops FK constraint, inserts all rows with correct parentId, re-adds FK at end.
-- Cannot fail under any Postgres SQL editor.

-- =========================================================
-- 1) SCHEMA ADDITIONS
-- =========================================================
ALTER TABLE "Category" ADD COLUMN IF NOT EXISTS "level" INTEGER NOT NULL DEFAULT 1;
ALTER TABLE "Category" ADD COLUMN IF NOT EXISTS "path" TEXT;
ALTER TABLE "Category" ADD COLUMN IF NOT EXISTS "hidden" BOOLEAN NOT NULL DEFAULT FALSE;
ALTER TABLE "Category" ADD COLUMN IF NOT EXISTS "aiGenerated" BOOLEAN NOT NULL DEFAULT FALSE;
ALTER TABLE "Category" ADD COLUMN IF NOT EXISTS "gender" TEXT;
CREATE INDEX IF NOT EXISTS "Category_level_parentId_idx" ON "Category"("level", "parentId");
CREATE INDEX IF NOT EXISTS "Category_path_idx" ON "Category"("path");
CREATE INDEX IF NOT EXISTS "Category_hidden_idx" ON "Category"("hidden");

CREATE TABLE IF NOT EXISTS "CategoryRedirect" (
  "id" TEXT PRIMARY KEY,
  "fromSlug" TEXT NOT NULL UNIQUE,
  "toSlug" TEXT NOT NULL,
  "permanent" BOOLEAN NOT NULL DEFAULT TRUE,
  "hitCount" INTEGER NOT NULL DEFAULT 0,
  "lastHitAt" TIMESTAMPTZ,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS "CategoryRedirect_fromSlug_idx" ON "CategoryRedirect"("fromSlug");

-- =========================================================
-- 2) DROP FK CONSTRAINT (will re-add at the end)
-- =========================================================
ALTER TABLE "Category" DROP CONSTRAINT IF EXISTS "Category_parentId_fkey";

-- =========================================================
-- 3) INSERT all 307 rows with real parentId values (FK is off)
-- =========================================================
ON CONFLICT ("slug") DO UPDATE SET
  "name" = EXCLUDED."name",
  "parentId" = EXCLUDED."parentId",
  "order" = EXCLUDED."order",
  "level" = EXCLUDED."level",
  "path" = EXCLUDED."path",
  "gender" = EXCLUDED."gender",
  "updatedAt" = NOW();

-- =========================================================
-- 4) RE-ADD FK CONSTRAINT now that all rows are present
-- =========================================================
ALTER TABLE "Category" ADD CONSTRAINT "Category_parentId_fkey"
  FOREIGN KEY ("parentId") REFERENCES "Category"("id")
  ON DELETE SET NULL ON UPDATE CASCADE;

-- =========================================================
-- 5) REDIRECTS for renamed / merged categories
-- =========================================================
ON CONFLICT ("fromSlug") DO UPDATE SET
  "toSlug" = EXCLUDED."toSlug",
  "updatedAt" = NOW();

-- =========================================================
-- 6) VERIFICATION: count by level
-- =========================================================
SELECT level, COUNT(*) as count FROM "Category" GROUP BY level ORDER BY level;